    // Copy src to local memory for faster access
    local_mem1[n] = src[n];
    __local_barrier();

    int current_val = local_mem1[n];

    // Process multiple rows (pyramid_height iterations)
    for (int h = 0; h < height; h++) {
        int row_idx = t + h;

        if (row_idx >= rows - 1) break;

        int min = current_val;
        if (n > 0) {
            int left = (n - 1 >= cols) ? current_val : local_mem1[n - 1];
            if (left < min) min = left;
        }
        if (n < cols - 1) {
            int right = (n + 1 >= cols) ? current_val : local_mem1[n + 1];
            if (right < min) min = right;
        }

        current_val = wall[(row_idx + 1) * cols + n] + min;

        // Store result for next iteration
        if (h < height - 1) {
            local_mem1[n] = current_val;
            __local_barrier();
        }
    }

    // Write final result
    dst[n] = current_val;

    // Store timing info in output buffer
    if (n == 0) {
        outputBuffer[0] = rows;
        outputBuffer[1] = cols;
        outputBuffer[2] = height;
    }
}

