const uint64_t LCG_M = 9223372036854775808ULL;
const uint64_t LCG_A = 2806196910506780709ULL;
const uint64_t LCG_C = 1ULL;

double LCG_random_double(uint64_t * seed)
{
    *seed = (LCG_A * (*seed) + LCG_C) % LCG_M;
    return (double) (*seed) / (double) LCG_M;
}

uint64_t fast_forward_LCG(uint64_t seed, uint64_t n)
{
    n = n % LCG_M;

    uint64_t a_new = 1;
    uint64_t c_new = 0;
    uint64_t a = LCG_A;
    uint64_t c = LCG_C;

    while(n > 0)
    {
        if(n & 1)
        {
            a_new *= a;
            c_new = c_new * a + c;
        }
        c *= (a + 1);
        a *= a;
        n >>= 1;
    }

    return (a_new * seed + c_new) % LCG_M;
}

